-- =============================================================
-- Fix 100-notes program-level: system_prompt, author_chat_system_prompt,
-- free_chat_welcome, author_chat_welcome
--
-- Корневые причины (см. docs/runbooks/chat-message-formatting.md):
--   R2 — programs.free_chat_welcome / author_chat_welcome не содержат
--        «ёлочек» → ChatWindow parseQuickReplies не находит стартовых
--        кнопок для free_chat и author_chat.
--   R3 — programs.system_prompt (для free_chat и всех тем) и
--        author_chat_system_prompt НЕ содержат блока про «ёлочки» →
--        AI не знает как форматировать quick replies.
--
-- Что делает:
--   1. Добавляет в конец programs.system_prompt полный блок
--      "## ФОРМАТ QUICK REPLIES" с правилами из mode-промптов.
--   2. То же для programs.author_chat_system_prompt.
--   3. Добавляет 4 «ёлочки» в конец programs.free_chat_welcome.
--   4. Добавляет 4 «ёлочки» в конец programs.author_chat_welcome.
-- =============================================================

BEGIN;

-- 1 + 2. Добавить блок "ФОРМАТ QUICK REPLIES" в оба program-level prompt
UPDATE programs
SET
  system_prompt = system_prompt || E'\n\n## ФОРМАТ QUICK REPLIES\n\n### Quick replies — ФОРМАТ (обязательный)\n\nЕсли хочешь предложить варианты ответа — пиши их в КОНЦЕ сообщения, каждый на отдельной строке, в «ёлочках»:\n\n«Вариант 1 от первого лица»\n«Вариант 2»\n«Мне сложно сформулировать»\n\nЭто ЕДИНСТВЕННЫЙ формат, который платформа рендерит как кнопки. Любой другой формат (список через "—" или "-", нумерация "1. ... 2. ...", блок «Что дальше?» с вопросами, перечисление через "•" как варианты ответа) будет показан пользователю plain-текстом без кнопок.\n\nПеред первой «ёлочкой» — пустая строка. Между «ёлочками» — одиночный перенос строки. НИКОГДА не склеивай «ёлочки» через пробел в одну строку.\n\nНЕПРАВИЛЬНО: [вопрос]? «Вариант 1» «Вариант 2»\nНЕПРАВИЛЬНО (все на одной строке): «Вариант 1» «Вариант 2» «Вариант 3»\nПРАВИЛЬНО:\n\n[твой ответ и один вопрос пользователю]\n\n«Вариант 1»\n«Вариант 2»\n«Мне сложно сформулировать»\n\nReplies — от первого лица, голос пользователя. Не вопросы к AI. Не задания. Последний reply в начале диалога — безопасный exit («Мне сложно сформулировать» или аналог).\n\n### Scaffolding fading (обязательный)\n\n- Turns 1–5: 3–4 reply в «ёлочках».\n- Turns 6–12: 2 reply.\n- Turns 13+: 0 reply или 1 fallback exit.\n\n### ЗАПРЕЩЕНО в формате ответа\n\n- Блок «Что дальше?» со списком вопросов — рендерится как markdown-текст, не как кнопки.\n- Список вариантов через "—" em-dash или "-" в начале строки.\n- Нумерованные списки «1. ... 2. ...» как варианты ответа.\n- «• Вариант» через буллет как reply — это визуально список, не кнопки.\n- Склеивание «ёлочек» в одну строку через пробел.\n- Несколько вопросов за ход — только один вопрос за сообщение.',

  author_chat_system_prompt = author_chat_system_prompt || E'\n\n## ФОРМАТ QUICK REPLIES\n\n### Quick replies — ФОРМАТ (обязательный)\n\nЕсли хочешь предложить варианты ответа — пиши их в КОНЦЕ сообщения, каждый на отдельной строке, в «ёлочках»:\n\n«Вариант 1 от первого лица»\n«Вариант 2»\n«Мне сложно сформулировать»\n\nЭто ЕДИНСТВЕННЫЙ формат, который платформа рендерит как кнопки. Любой другой формат (список через "—" или "-", нумерация "1. ... 2. ...", блок «Что дальше?» с вопросами, перечисление через "•" как варианты ответа) будет показан пользователю plain-текстом без кнопок.\n\nПеред первой «ёлочкой» — пустая строка. Между «ёлочками» — одиночный перенос строки. НИКОГДА не склеивай «ёлочки» через пробел в одну строку.\n\nНЕПРАВИЛЬНО: [вопрос]? «Вариант 1» «Вариант 2»\nНЕПРАВИЛЬНО (все на одной строке): «Вариант 1» «Вариант 2» «Вариант 3»\nПРАВИЛЬНО:\n\n[твой ответ и один вопрос пользователю]\n\n«Вариант 1»\n«Вариант 2»\n«Мне сложно сформулировать»\n\nReplies — от первого лица пользователя. Не вопросы к тебе (к Петру). Не задания. Последний reply в начале диалога — безопасный exit («Мне сложно сформулировать» или аналог).\n\n### Scaffolding fading (обязательный)\n\n- Turns 1–5: 3–4 reply в «ёлочках».\n- Turns 6–12: 2 reply.\n- Turns 13+: 0 reply или 1 fallback exit.\n\n### ЗАПРЕЩЕНО в формате ответа\n\n- Блок «Что дальше?» со списком вопросов — рендерится как markdown-текст, не как кнопки.\n- Список вариантов через "—" em-dash или "-" в начале строки.\n- Нумерованные списки «1. ... 2. ...» как варианты ответа.\n- «• Вариант» через буллет как reply — это визуально список, не кнопки.\n- Склеивание «ёлочек» в одну строку через пробел.\n- Несколько вопросов за ход — только один вопрос за сообщение.'
WHERE slug = '100-notes';

-- 3. Добавить 4 «ёлочки» в конец free_chat_welcome
-- (синхронизировано с program_modes.welcome_replies для free_chat)
UPDATE programs
SET free_chat_welcome = free_chat_welcome || E'\n\n«Как перестать развиваться через боль?»\n«Что делать, когда нет сил ни на что?»\n«Как понять, моя это цель или навязанная?»\n«Просто хочу поговорить о том, что на душе»'
WHERE slug = '100-notes';

-- 4. Добавить 4 «ёлочки» в конец author_chat_welcome
-- (синхронизировано с program_modes.welcome_replies для author_chat
--  но inner «...» убраны — они ломают parseQuickReplies regex)
UPDATE programs
SET author_chat_welcome = author_chat_welcome || E'\n\n«Пётр, как ты справляешься со страхом провала?»\n«Что для тебя значит развитие через удовольствие?»\n«Как ты понял, что пора закрыть Бизнес Молодость?»\n«Расскажи о своём самом большом провале»'
WHERE slug = '100-notes';

-- Верификация
SELECT
  slug,
  system_prompt LIKE '%## ФОРМАТ QUICK REPLIES%' as base_has_quickrules,
  author_chat_system_prompt LIKE '%## ФОРМАТ QUICK REPLIES%' as author_has_quickrules,
  free_chat_welcome LIKE E'%«%»' as free_welcome_ends_with_elochki,
  author_chat_welcome LIKE E'%«%»' as author_welcome_ends_with_elochki,
  (LENGTH(free_chat_welcome) - LENGTH(REPLACE(free_chat_welcome, '«', ''))) as free_welcome_elochki_count,
  (LENGTH(author_chat_welcome) - LENGTH(REPLACE(author_chat_welcome, '«', ''))) as author_welcome_elochki_count
FROM programs
WHERE slug = '100-notes';

COMMIT;
